import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"河图洛书与中医","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/02-河图洛书与中医.md","filePath":"tcm-data/09-医易同源/02-河图洛书与中医.md","lastUpdated":1781084559000}'),s={name:"tcm-data/09-医易同源/02-河图洛书与中医.md"};function d(i,t,r,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="河图洛书与中医" tabindex="-1">河图洛书与中医 <a class="header-anchor" href="#河图洛书与中医" aria-label="Permalink to &quot;河图洛书与中医&quot;">​</a></h1><blockquote><p>河图、洛书——中国数理文化的源头 中医&quot;取象比类&quot;的数理根基</p></blockquote><hr><h2 id="一、河图——天地生成之数" tabindex="-1">一、河图——天地生成之数 <a class="header-anchor" href="#一、河图——天地生成之数" aria-label="Permalink to &quot;一、河图——天地生成之数&quot;">​</a></h2><h3 id="河图图式" tabindex="-1">河图图式 <a class="header-anchor" href="#河图图式" aria-label="Permalink to &quot;河图图式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        火（7）</span></span>
<span class="line"><span>          ↑</span></span>
<span class="line"><span>木（3）→ 土（5·10）← 金（4·9）</span></span>
<span class="line"><span>          ↓</span></span>
<span class="line"><span>        水（1·6）</span></span></code></pre></div><h3 id="河图数" tabindex="-1">河图数 <a class="header-anchor" href="#河图数" aria-label="Permalink to &quot;河图数&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">数</th><th style="text-align:left;">五行</th><th style="text-align:left;">方向</th><th style="text-align:left;">中医对应</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>1·6</strong></td><td style="text-align:left;">水（天一生水，地六成之）</td><td style="text-align:left;">北</td><td style="text-align:left;">肾（水）</td></tr><tr><td style="text-align:center;"><strong>2·7</strong></td><td style="text-align:left;">火（地二生火，天七成之）</td><td style="text-align:left;">南</td><td style="text-align:left;">心（火）</td></tr><tr><td style="text-align:center;"><strong>3·8</strong></td><td style="text-align:left;">木（天三生木，地八成之）</td><td style="text-align:left;">东</td><td style="text-align:left;">肝（木）</td></tr><tr><td style="text-align:center;"><strong>4·9</strong></td><td style="text-align:left;">金（地四生金，天九成之）</td><td style="text-align:left;">西</td><td style="text-align:left;">肺（金）</td></tr><tr><td style="text-align:center;"><strong>5·10</strong></td><td style="text-align:left;">土（天五生土，地十成之）</td><td style="text-align:left;">中</td><td style="text-align:left;">脾（土）</td></tr></tbody></table><h3 id="河图的医学意义" tabindex="-1">河图的医学意义 <a class="header-anchor" href="#河图的医学意义" aria-label="Permalink to &quot;河图的医学意义&quot;">​</a></h3><p><strong>1. 五脏生成数</strong> 每个脏都有一个&quot;生数&quot;（先天）和一个&quot;成数&quot;（后天）：</p><ul><li>肾水生数1 → 是先天之本（根）</li><li>脾土生数5 → 是后天之本（中轴）</li></ul><p><strong>2. 左升右降</strong> 河图的左（3·8木）右（4·9金）分布，就是黄元御&quot;左升右降&quot;模型的数理基础。</p><p><strong>3. 土居中轴</strong> 5·10土居中——黄元御&quot;中气如轴&quot;的数理来源。</p><hr><h2 id="二、洛书——九宫变化之象" tabindex="-1">二、洛书——九宫变化之象 <a class="header-anchor" href="#二、洛书——九宫变化之象" aria-label="Permalink to &quot;二、洛书——九宫变化之象&quot;">​</a></h2><h3 id="洛书数-九宫" tabindex="-1">洛书数（九宫） <a class="header-anchor" href="#洛书数-九宫" aria-label="Permalink to &quot;洛书数（九宫）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    东南        南         西南</span></span>
<span class="line"><span>    巽4       离9       坤2</span></span>
<span class="line"><span>      </span></span>
<span class="line"><span>    东         中         西</span></span>
<span class="line"><span>    震3       中5       兑7</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    东北        北         西北</span></span>
<span class="line"><span>    艮8       坎1       乾6</span></span></code></pre></div><p>口诀：<strong>戴九履一，左三右七，二四为肩，六八为足，五居中央。</strong></p><h3 id="洛书的医学意义" tabindex="-1">洛书的医学意义 <a class="header-anchor" href="#洛书的医学意义" aria-label="Permalink to &quot;洛书的医学意义&quot;">​</a></h3><p><strong>1. 九宫八风</strong> 《黄帝内经·灵枢·九宫八风》以洛书九宫定位八种风邪：</p><ul><li>从各宫来的风 → 对应不同的致病特点</li><li>避风如避箭——尤其是从&quot;虚乡&quot;来的风</li></ul><p><strong>2. 灵龟八法（针灸）</strong> 根据洛书数，结合时辰取穴：</p><ul><li>按日时干支推算</li><li>对应八脉交会穴</li><li>用于针灸开穴</li></ul><p><strong>3. 五运六气的方位基础</strong></p><ul><li>洛书的九宫对应五脏六腑的位置</li><li>九宫数的变化对应运气流转</li></ul><hr><h2 id="三、河图洛书的关系" tabindex="-1">三、河图洛书的关系 <a class="header-anchor" href="#三、河图洛书的关系" aria-label="Permalink to &quot;三、河图洛书的关系&quot;">​</a></h2><blockquote><p><strong>「河图主常，洛书主变。」</strong></p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">河图</th><th style="text-align:left;">洛书</th></tr></thead><tbody><tr><td style="text-align:left;">性质</td><td style="text-align:left;">体（正常状态）</td><td style="text-align:left;">用（变化状态）</td></tr><tr><td style="text-align:left;">对应</td><td style="text-align:left;">生理</td><td style="text-align:left;">病理</td></tr><tr><td style="text-align:left;">方向</td><td style="text-align:left;">东南西北中+顺生</td><td style="text-align:left;">九宫+逆克</td></tr><tr><td style="text-align:left;">中医应用</td><td style="text-align:left;">五脏生理功能</td><td style="text-align:left;">病证传变+取穴</td></tr></tbody></table><p><strong>简单理解</strong>：</p><ul><li>河图 = 人健康时的&quot;一气周流&quot;（左升右降，中土枢轴）</li><li>洛书 = 人得病时的&quot;气机逆乱&quot;（九宫移位，升降失常）</li></ul><hr><h2 id="四、河洛在普光-普明体质中的应用" tabindex="-1">四、河洛在普光/普明体质中的应用 <a class="header-anchor" href="#四、河洛在普光-普明体质中的应用" aria-label="Permalink to &quot;四、河洛在普光/普明体质中的应用&quot;">​</a></h2><h3 id="普光-壬戌年生" tabindex="-1">普光（壬戌年生） <a class="header-anchor" href="#普光-壬戌年生" aria-label="Permalink to &quot;普光（壬戌年生）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">河洛分析</th><th style="text-align:left;">临床对应</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>河图</strong></td><td style="text-align:left;">水数1·6</td><td style="text-align:left;">肾水寒，1之生数不足→阳虚</td></tr><tr><td style="text-align:left;"><strong>洛书</strong></td><td style="text-align:left;">坎位（北）1</td><td style="text-align:left;">病在少阴（肾）</td></tr><tr><td style="text-align:left;">治则</td><td style="text-align:left;">温坎水</td><td style="text-align:left;">附子温肾阳</td></tr></tbody></table><h3 id="普明-壬戌年·女" tabindex="-1">普明（壬戌年·女） <a class="header-anchor" href="#普明-壬戌年·女" aria-label="Permalink to &quot;普明（壬戌年·女）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">河洛分析</th><th style="text-align:left;">临床对应</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>河图</strong></td><td style="text-align:left;">土数5·10</td><td style="text-align:left;">脾土湿，中气不足</td></tr><tr><td style="text-align:left;"><strong>洛书</strong></td><td style="text-align:left;">中宫5</td><td style="text-align:left;">病在脾胃（中枢不利）</td></tr><tr><td style="text-align:left;">治则</td><td style="text-align:left;">培中土</td><td style="text-align:left;">人参白术健脾</td></tr></tbody></table><hr><h2 id="五、经典原文" tabindex="-1">五、经典原文 <a class="header-anchor" href="#五、经典原文" aria-label="Permalink to &quot;五、经典原文&quot;">​</a></h2><blockquote><p><strong>《易传·系辞》</strong>：「河出图，洛出书，圣人则之。」</p></blockquote><blockquote><p><strong>《黄帝内经·灵枢·九宫八风》</strong>：「太一常以冬至之日，居叶蛰之宫四十六日……明日居天留四十六日……」</p></blockquote><blockquote><p><strong>张介宾《类经图翼》</strong>：「河图者，五行顺行，相生之序也；洛书者，五行逆布，相克之序也。」</p></blockquote><blockquote><p><strong>黄元御《四圣心源》</strong>：「土为四象之母，实生四象，曰水、火、金、木而土寄旺于四季。」（←河图思想的直接应用）</p></blockquote><hr><p><em>本条目可扩展至河洛数理在方剂配伍中的应用（如用药剂量中的生成数原理）。</em></p>`,45)])])}const x=e(s,[["render",d]]);export{c as __pageData,x as default};
